    private SecuritySettings? _settings;
    private bool _twoFactorEnabled;
    private List<ActiveSession> _sessions = new();

    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _changingPassword;

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private bool _loading = true;
    private string? _statusMessage;
    private bool _isError;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _settings.TwoFactorEnabled;
        _sessions = _settings.Sessions.ToList();
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordPanelOpen = false;
            _statusMessage = "Password updated successfully!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _passwordError = ex.Message;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            _statusMessage = $"Session on {_sessionToRevoke.Device} revoked.";
            _isError = false;
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to revoke session: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _revoking = false;
        }
    }
}

@using sv_d87940afa2cf40a8aebc14c1527f90c5.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4>Appearance</h4>

    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        @* Theme *@
        <div class="mb-4">
            <h6 class="fw-semibold mb-2">Theme</h6>
            @foreach (var theme in _themes)
            {
                <div class="form-check form-check-inline">
                    <input class="form-check-input" type="radio" name="theme"
                           id="@($"theme-{theme.ToLower()}")"
                           value="@theme"
                           checked="@(_theme == theme)"
                           @onchange="() => _theme = theme" />
                    <label class="form-check-label" for="@($"theme-{theme.ToLower()}")">@theme</label>
                </div>
            }
        </div>

        @* Font Size *@
        <div class="mb-4">
            <h6 class="fw-semibold mb-2">Font Size</h6>
            @foreach (var size in _fontSizes)
            {
                <div class="form-check form-check-inline">
                    <input class="form-check-input" type="radio" name="fontSize"
                           id="@($"fs-{size.ToLower()}")"
                           value="@size"
                           checked="@(_fontSize == size)"
                           @onchange="() => _fontSize = size" />
                    <label class="form-check-label" for="@($"fs-{size.ToLower()}")">@size</label>
                </div>
            }
        </div>

        @* Language *@
        <div class="mb-4">
            <h6 class="fw-semibold mb-2">Language</h6>
            <select class="form-select" style="max-width: 250px;"
                    @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang.Key">@lang.Value</option>
                }
            </select>
        </div>

        @* Compact Mode *@
        <div class="mb-4">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                <label class="form-check-label" for="compactMode">Compact Mode</label>
            </div>
        </div>

        @* Live Preview *@
        <div class="mb-4">
            <h6 class="fw-semibold mb-2">Preview</h6>
            <div class="appearance-preview @PreviewThemeClass" style="@PreviewFontStyle">
                <div class="preview-header">
                    <strong>Dashboard</strong>
                    @if (_compactMode)
                    {
                        <span class="badge bg-secondary ms-2" style="font-size: 0.7em;">compact</span>
                    }
                </div>
                <div class="preview-body" style="@(_compactMode ? "padding: 0.5rem;" : "padding: 1rem;")">
                    <p style="margin-bottom: @(_compactMode ? "0.25rem" : "0.5rem");">
                        This is a preview of your selected appearance settings.
                    </p>
                    <p style="margin-bottom: 0;">
                        Theme: <strong>@_theme</strong> · Font: <strong>@_fontSize</strong> · Language: <strong>@_languages.GetValueOrDefault(_language, _language)</strong>
                    </p>
                </div>
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save")
        </button>
    }
</div>

@code {
    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語",
    };

    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "preview-dark",
        "Light" => "preview-light",
        _ => "preview-system",
    };

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;",
    };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _statusMessage = "Appearance settings saved!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

