@* Vertical navigation tabs for the settings dashboard *@

<nav class="settings-sidebar">
    <h5 class="settings-sidebar-title">Settings</h5>
    <ul class="settings-nav">
        @foreach (var section in _sections)
        {
            <li class="settings-nav-item">
                <button class="settings-nav-link @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="settings-nav-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired]
    public string ActiveSection { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> OnSectionChanged { get; set; }

    private readonly record struct NavItem(string Key, string Label, string Icon);

    private static readonly NavItem[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];
}

@using sv_d87940afa2cf40a8aebc14c1527f90c5.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h4>Notifications</h4>

    @if (_loading)
    {
        <p class="text-muted">Loading notification preferences…</p>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="mb-4">
            <h6 class="fw-semibold mb-3">General</h6>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Muted Channels</h6>
            @if (_allChannels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                @foreach (var channel in _allChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private List<string> _allChannels = new();

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        _allChannels = prefs.MutedChannels.Count > 0
            ? prefs.MutedChannels.ToList()
            : ["general", "announcements", "random", "engineering", "design"];
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _statusMessage = "Notification preferences saved!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
