@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "profile";
}

.settings-dashboard {
    display: flex;
    gap: 2rem;
    min-height: 70vh;
}

/* Sidebar */
.settings-sidebar {
    min-width: 200px;
    max-width: 220px;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

.settings-sidebar-title {
    padding: 0.5rem 0.75rem;
    margin-bottom: 0.5rem;
    color: #6c757d;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav-item {
    margin-bottom: 0.25rem;
}

.settings-nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: none;
    border-radius: 0.375rem;
    background: transparent;
    color: #212529;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.settings-nav-link:hover {
    background-color: #f8f9fa;
}

.settings-nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

.settings-nav-icon {
    font-size: 1.1rem;
}

/* Content area */
.settings-content {
    flex: 1;
    min-width: 0;
}

.settings-section h4 {
    margin-bottom: 1.5rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid #dee2e6;
}

/* Profile avatar */
.avatar-preview {
    width: 72px;
    height: 72px;
    border-radius: 50%;
    overflow: hidden;
    border: 2px solid #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f8f9fa;
    flex-shrink: 0;
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2rem;
}

/* Appearance preview */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    max-width: 500px;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid inherit;
}

.preview-light {
    background: #ffffff;
    color: #212529;
    border-color: #dee2e6;
}

.preview-light .preview-header {
    background: #f8f9fa;
    border-color: #dee2e6;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-dark .preview-header {
    background: #2a2a3d;
    border-color: #444;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
    border-color: #aaa;
}

.preview-system .preview-header {
    background: #f0f0f0;
    border-color: #aaa;
}

.preview-system .preview-body {
    background: #fff;
}

